function findCoquelleFRBracket(ml){
  const b=RAW.coquelle_fr_brackets;
  for(let i=0;i<b.length;i++) if(ml<=b[i][1]+0.001) return i;
  return b.length-1;
}
function findMLIndex(ml,arr){
  for(let i=0;i<arr.length;i++) if(arr[i]>=ml-0.001) return i;
  return arr.length-1;
}
function calcHeppnerFR(dept,weight){
  const p=RAW.heppner_fr[dept];
  if(!p) return null;
  if(weight<=9)  return p[0];
  if(weight<=19) return p[1];
  if(weight<=29) return p[2];
  if(weight<=39) return p[3];
  if(weight<=49) return p[4];
  if(weight<=59) return p[5];
  if(weight<=69) return p[6];
  if(weight<=79) return p[7];
  if(weight<=89) return p[8];
  if(weight<=99) return p[9];
  if(weight<=250 &&p[10]!=null) return (weight/100)*p[10];
  if(weight<=500 &&p[11]!=null) return (weight/100)*p[11];
  if(weight<=1000&&p[12]!=null) return (weight/100)*p[12];
  return p[13]!=null?(weight/100)*p[13]:null;
}
function calcCoupePoids(dept,weight){
  const p=RAW.coupe_poids[dept];
  if(!p) return null;
  if(weight<=10) return p[0];
  if(weight<=20) return p[1];
  if(weight<=30) return p[2];
  if(weight<=40) return p[3];
  if(weight<=50) return p[4];
  if(weight<=60) return p[5];
  if(weight<=70) return p[6];
  if(weight<=80) return p[7];
  if(weight<=90) return p[8];
  if(weight<=100)return p[9];
  if(weight<=250 &&p[10]!=null) return (weight/100)*p[10];
  if(weight<=500 &&p[11]!=null) return (weight/100)*p[11];
  if(weight<=1000&&p[12]!=null) return (weight/100)*p[12];
  return null;
}
function calcHeppnerIntl(cc,weight){
  const pr=RAW.heppner_countries[cc];
  if(!pr||!pr.length) return null;
  if(weight<=29)   return pr[0];
  if(weight<=69)   return pr[1];
  if(weight<=100)  return pr[2];
  if(weight<=250)  return pr[3]!=null?(weight/100)*pr[3]:null;
  if(weight<=500)  return pr[4]!=null?(weight/100)*pr[4]:null;
  if(weight<=1000) return pr[5]!=null?(weight/100)*pr[5]:null;
  if(weight<=1500) return pr[6]!=null?(weight/100)*pr[6]:null;
  if(weight<=2000) return pr[7]!=null?(weight/100)*pr[7]:null;
  return pr[8]!=null?(weight/100)*pr[8]:null;
}
function getDimotransBeZone(pc){
  const p=parseInt(pc,10);
  if(isNaN(p)) return null;
  if(p>=7000&&p<=8999) return 0;
  if((p>=1000&&p<=3999)||(p>=5000&&p<=5399)||(p>=6000&&p<=6399)||(p>=9000&&p<=9999)) return 1;
  if((p>=4000&&p<=4999)||(p>=6400&&p<=6499)) return 2;
  if((p>=5500&&p<=5599)||(p>=6600&&p<=6999)) return 3;
  return 1;
}
function getDimotransBePrice(pc,ml){
  const zone=getDimotransBeZone(pc);
  if(zone===null) return null;
  const rows=RAW.dimotrans_be;
  for(let i=rows.length-1;i>=0;i--){
    if(rows[i].mp<=ml+0.001){
      const z=rows[i].zones;
      return z&&z[zone]!=null?z[zone]:null;
    }
  }
  return rows[0].zones[zone];
}
function r2(v){ return v!=null?Math.round(v*100)/100:null; }

// ── Calculation engine ───────────────────────────────────────────
function calculate({destType,dept,postalCodeBE,country,nbPal,ml,weight,filterMode}){
  const results=[];
  const addResult=(carrier,service,price,delayH,serviceMode)=>{
    if(price==null||price<=0||isNaN(price)) return;
    const express=delayH<=24;
    const standard=delayH>24&&delayH<=48;
    const slow=delayH>48;
    if(filterMode==='express'&&!express) return;
    if(filterMode==='standard'&&!standard) return;
    if(filterMode==='slow'&&!slow) return;
    results.push({carrier,service,price:r2(price),delayH,express,serviceMode});
  };

  if(destType==='france'){
    const d=dept.trim().padStart(2,'0');
    const nbP=parseInt(nbPal)||0;
    const mlV=parseFloat(ml)||0;
    const wV=parseFloat(weight)||0;

    if(nbP>=1&&nbP<=5&&RAW.coupe_pal[d])
      addResult('Coupé','Tarif palette',RAW.coupe_pal[d][nbP-1],24,'palette');
    if(wV>0)
      addResult('Coupé','Tarif poids',calcCoupePoids(d,wV),24,'poids');
    if(mlV>0&&RAW.coquelle_fr[d])
      addResult('Coquelle','Réseau France',RAW.coquelle_fr[d][findCoquelleFRBracket(mlV)],48,'ml');
    if(mlV>0&&RAW.ceva_fr[d])
      addResult('Ceva','Affrètement France',RAW.ceva_fr[d][findMLIndex(mlV,RAW.ceva_fr_ml)],48,'ml');
    if(mlV>0&&RAW.dimotrans_fr[d])
      addResult('Dimotrans','France',RAW.dimotrans_fr[d][findMLIndex(mlV,RAW.dimotrans_fr_ml)],48,'ml');
    if(wV>0)
      addResult('Heppner','Messagerie France',calcHeppnerFR(d,wV),24,'poids');
    if(nbP>=1&&RAW.heppner_aff_fr[d])
      addResult('Heppner','Affrètement France',RAW.heppner_aff_fr[d][nbP-1],48,'palette');
  }
  else if(destType==='belgique'){
    const pc=postalCodeBE.trim();
    const mlV=parseFloat(ml)||0;
    const nbP=parseInt(nbPal)||0;
    const wV=parseFloat(weight)||0;
    if(mlV>0){
      const zone=(String(pc).padStart(4,'0')).substring(0,2);
      const b=RAW.coquelle_be_brackets;
      let idx=0;
      for(let i=0;i<b.length;i++){if(mlV<=b[i][1]+0.001){idx=i;break;}idx=b.length-1;}
      const prices=RAW.coquelle_be[zone];
      if(prices) addResult('Coquelle','Belgique',prices[idx],48,'ml');
      addResult('Dimotrans','Belgique/Luxembourg',getDimotransBePrice(pc,mlV),48,'ml');
    }
    if(wV>0)
      addResult('Heppner','Messagerie Belgique',calcHeppnerIntl('BE',wV),48,'poids');
  }
  else if(destType==='international'){
    const cc=country.toUpperCase();
    const wV=parseFloat(weight)||0;
    const delayDays=COUNTRY_DELAYS[cc]||4;
    if(wV>0)
      addResult('Heppner',`Messagerie ${COUNTRY_NAMES[cc]||cc}`,calcHeppnerIntl(cc,wV),delayDays*24,'poids');
  }

  results.sort((a,b)=>a.delayH-b.delayH||a.price-b.price);
  return results;
}

// ── Contact helpers ──────────────────────────────────────────────
function openContact(carrier,contacts){
  const c=contacts[carrier];
  if(!c) return;
  if(c.type==='url') window.open(c.value,'_blank','noopener,noreferrer');
  else window.location.href=`mailto:${c.value}?subject=Demande%20de%20tarif%20SIFA%20-%20${encodeURIComponent(carrier)}&body=Bonjour%2C%0A%0ANous%20souhaitons%20un%20tarif%20pour%20une%20exp%C3%A9dition.%0A%0ACordialement%2C%0ASIFA`;
}

