// ── Carrier color palette ────────────────────────────────────────
const CARRIER_COLORS = {
  'Coupé':     '#22d3ee',
  'Coquelle':  '#a78bfa',
  'Ceva':      '#34d399',
  'Dimotrans': '#fbbf24',
  'Heppner':   '#f472b6',
  'DSV':       '#60a5fa',
};
const carrierColor = c => CARRIER_COLORS[c] || '#94a3b8';
const carrierInitial = c => c.charAt(0).toUpperCase();

const ss = {
  bg:'#0a0e17', card:'#111827', border:'#1e293b', text:'#f1f5f9',
  muted:'#94a3b8', accent:'#22d3ee', input:{background:'#0f172a',border:'1px solid #1e293b',borderRadius:8,padding:'10px 14px',color:'#f1f5f9',fontSize:14,outline:'none',boxSizing:'border-box',width:'100%'},
  btn:(col)=>({background:col||'#22d3ee',color:'#0a0e17',border:'none',borderRadius:8,padding:'9px 18px',fontSize:13,fontWeight:700,cursor:'pointer',display:'inline-flex',alignItems:'center',gap:6}),
  ghost:{background:'transparent',color:'#cbd5e1',border:'1px solid #1e293b',borderRadius:8,padding:'8px 14px',fontSize:12,fontWeight:600,cursor:'pointer',display:'inline-flex',alignItems:'center',gap:6},
  label:{fontSize:11,fontWeight:600,color:'#94a3b8',textTransform:'uppercase',letterSpacing:1,display:'block',marginBottom:6},
};

const delayLabel=h=>{
  if(h<=24) return {text:'24h — J+1',color:'#34d399',badge:'EXPRESS'};
  if(h<=48) return {text:'48h — J+2',color:'#fbbf24',badge:'STANDARD'};
  if(h<=72) return {text:'72h — J+3',color:'#f97316',badge:'STANDARD'};
  if(h<=96) return {text:'4 jours',color:'#f97316',badge:'STANDARD'};
  return {text:Math.round(h/24)+' jours',color:'#f87171',badge:'LENT'};
};

// ── Contact Manager Modal ────────────────────────────────────────
function ContactManager({contacts,onSave,onClose}){
  const [local,setLocal]=useState(()=>JSON.parse(JSON.stringify(contacts)));
  const [newName,setNewName]=useState('');
  const [newType,setNewType]=useState('email');
  const [newVal,setNewVal]=useState('');

  const carriers=Object.keys(local);
  const update=(name,field,val)=>setLocal(prev=>({...prev,[name]:{...prev[name],[field]:val}}));
  const remove=(name)=>setLocal(prev=>{const n={...prev};delete n[name];return n;});
  const add=()=>{
    if(!newName.trim()||!newVal.trim()) return;
    setLocal(prev=>({...prev,[newName.trim()]:{type:newType,value:newVal.trim(),label:newType==='url'?'Portail '+newName.trim():'Mail '+newName.trim()}}));
    setNewName('');setNewVal('');
  };
  const save=()=>{
    try{localStorage.setItem(CONTACT_STORAGE_KEY,JSON.stringify(local));}catch(e){}
    onSave(local);
  };

  return (
    <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,.7)',display:'flex',alignItems:'center',justifyContent:'center',zIndex:1000,padding:16}}>
      <div style={{background:ss.card,border:'1px solid #334155',borderRadius:16,width:'100%',maxWidth:560,maxHeight:'85vh',display:'flex',flexDirection:'column'}}>
        <div style={{padding:'20px 24px',borderBottom:'1px solid #1e293b',display:'flex',justifyContent:'space-between',alignItems:'center'}}>
          <div>
            <h2 style={{fontSize:16,fontWeight:700,margin:0}}>Contacts transporteurs</h2>
            <p style={{fontSize:12,color:ss.muted,margin:'2px 0 0'}}>URL de portail ou adresse email par transporteur</p>
          </div>
          <button onClick={onClose} style={{...ss.ghost,padding:'6px 8px'}}><IconX/></button>
        </div>
        <div style={{padding:'20px 24px',overflowY:'auto',flex:1}}>
          {carriers.map(name=>(
            <div key={name} style={{marginBottom:14,padding:'14px 16px',background:'#0f172a',borderRadius:10,border:'1px solid #1e293b'}}>
              <div style={{display:'flex',alignItems:'center',gap:10,marginBottom:10}}>
                <div style={{width:32,height:32,borderRadius:8,background:carrierColor(name)+'22',border:`1px solid ${carrierColor(name)}44`,display:'flex',alignItems:'center',justifyContent:'center',fontSize:13,fontWeight:700,color:carrierColor(name),flexShrink:0}}>
                  {carrierInitial(name)}
                </div>
                <span style={{fontWeight:700,fontSize:14,color:ss.text,flex:1}}>{name}</span>
                <button onClick={()=>remove(name)} style={{background:'transparent',border:'none',cursor:'pointer',color:'#ef4444',padding:4}}><IconTrash/></button>
              </div>
              <div style={{display:'flex',gap:8,alignItems:'center'}}>
                <select value={local[name].type} onChange={e=>update(name,'type',e.target.value)}
                  style={{...ss.input,width:100,padding:'8px 10px',fontSize:12,flexShrink:0}}>
                  <option value="email">Email</option>
                  <option value="url">Site web</option>
                </select>
                <input value={local[name].value} onChange={e=>update(name,'value',e.target.value)}
                  placeholder={local[name].type==='email'?'contact@transporteur.fr':'https://...'}
                  style={{...ss.input,padding:'8px 12px',fontSize:12}}/>
              </div>
            </div>
          ))}
          {/* Add new */}
          <div style={{padding:'14px 16px',background:'rgba(34,211,238,.05)',borderRadius:10,border:'1px dashed #334155'}}>
            <p style={{...ss.label,marginBottom:10}}>Ajouter un transporteur</p>
            <div style={{display:'flex',gap:8,flexWrap:'wrap'}}>
              <input value={newName} onChange={e=>setNewName(e.target.value)} placeholder="Nom"
                style={{...ss.input,width:110,padding:'8px 10px',fontSize:12,flexShrink:0}}/>
              <select value={newType} onChange={e=>setNewType(e.target.value)}
                style={{...ss.input,width:90,padding:'8px 10px',fontSize:12,flexShrink:0}}>
                <option value="email">Email</option>
                <option value="url">Site web</option>
              </select>
              <input value={newVal} onChange={e=>setNewVal(e.target.value)}
                placeholder={newType==='email'?'email@...':'https://...'}
                style={{...ss.input,flex:1,padding:'8px 10px',fontSize:12,minWidth:120}}/>
              <button onClick={add} style={{...ss.btn('#22d3ee'),padding:'8px 14px',flexShrink:0}}><IconPlus/></button>
            </div>
          </div>
        </div>
        <div style={{padding:'16px 24px',borderTop:'1px solid #1e293b',display:'flex',gap:10,justifyContent:'flex-end'}}>
          <button onClick={onClose} style={ss.ghost}>Annuler</button>
          <button onClick={save} style={ss.btn('#22d3ee')}>Enregistrer</button>
        </div>
      </div>
    </div>
  );
}

// ── Result Card ──────────────────────────────────────────────────
function ResultCard({result,rank,contacts}){
  const {carrier,service,price,delayH,express,serviceMode}=result;
  const dl=delayLabel(delayH);
  const col=carrierColor(carrier);
  const contact=contacts[carrier];
  const medals=['🥇','🥈','🥉'];
  const isTop=rank<3;

  return (
    <div style={{background:ss.card,border:`1px solid ${isTop&&rank===0?col+'55':'#1e293b'}`,borderRadius:14,overflow:'hidden',position:'relative'}}>
      {/* Colored top stripe */}
      <div style={{height:4,background:col}}/>
      <div style={{padding:'16px 20px'}}>
        {/* Header: carrier + rank */}
        <div style={{display:'flex',alignItems:'flex-start',justifyContent:'space-between',marginBottom:12}}>
          <div style={{display:'flex',alignItems:'center',gap:12}}>
            <div style={{width:44,height:44,borderRadius:10,background:col+'20',border:`2px solid ${col}55`,display:'flex',alignItems:'center',justifyContent:'center',fontSize:18,fontWeight:800,color:col,flexShrink:0,letterSpacing:-1}}>
              {carrierInitial(carrier)}
            </div>
            <div>
              <div style={{fontSize:18,fontWeight:800,color:ss.text,letterSpacing:-.3}}>{carrier}</div>
              <div style={{fontSize:12,color:ss.muted,marginTop:1}}>{service}</div>
            </div>
          </div>
          {isTop&&<span style={{fontSize:22}}>{medals[rank]}</span>}
        </div>

        {/* Price + delay */}
        <div style={{display:'flex',alignItems:'flex-end',gap:16,marginBottom:14}}>
          <div>
            <div style={{fontSize:11,color:ss.muted,fontWeight:600,textTransform:'uppercase',letterSpacing:.5,marginBottom:2}}>Prix HT</div>
            <div style={{fontSize:26,fontWeight:800,fontFamily:'monospace',color:col}}>{price.toFixed(2)} <span style={{fontSize:14,color:ss.muted,fontWeight:400}}>€</span></div>
          </div>
          <div style={{flex:1}}>
            <div style={{fontSize:11,color:ss.muted,fontWeight:600,textTransform:'uppercase',letterSpacing:.5,marginBottom:2}}>Délai</div>
            <div style={{fontSize:15,fontWeight:700,color:dl.color}}>{dl.text}</div>
          </div>
        </div>

        {/* Badges */}
        <div style={{display:'flex',gap:8,flexWrap:'wrap',marginBottom:14}}>
          <span style={{fontSize:10,fontWeight:700,padding:'3px 10px',borderRadius:20,
            background:express?'rgba(52,211,153,.15)':'rgba(251,191,36,.12)',
            color:express?'#34d399':'#fbbf24',border:`1px solid ${express?'#34d39944':'#fbbf2444'}`}}>
            {dl.badge}
          </span>
          <span style={{fontSize:10,fontWeight:600,padding:'3px 10px',borderRadius:20,
            background:'rgba(148,163,184,.08)',color:'#94a3b8',border:'1px solid #1e293b'}}>
            {serviceMode==='palette'?'Palettes':serviceMode==='poids'?'Au poids':'ML'}
          </span>
        </div>

        {/* Contact button */}
        {contact&&(
          <button onClick={()=>openContact(carrier,contacts)}
            style={{width:'100%',background:col+'15',border:`1px solid ${col}44`,borderRadius:8,padding:'9px 14px',
              color:col,fontSize:12,fontWeight:600,cursor:'pointer',display:'flex',alignItems:'center',justifyContent:'center',gap:8}}>
            {contact.type==='url'?<IconLink/>:<IconMail/>}
            {contact.type==='url'?'Ouvrir le portail':'Envoyer un email'}
          </button>
        )}
      </div>
    </div>
  );
}

