// ── Main App ─────────────────────────────────────────────────────
function App(){
  const [destType,setDestType]=useState('france');
  const [dept,setDept]=useState('59');
  const [postalCodeBE,setPostalCodeBE]=useState('1000');
  const [country,setCountry]=useState('DE');
  const [shipMode,setShipMode]=useState('pal');
  const [nbPal,setNbPal]=useState('2');
  const [ml,setMl]=useState('0.8');
  const [weight,setWeight]=useState('100');
  const [filterMode,setFilterMode]=useState('all');
  const [results,setResults]=useState(null);
  const [showManager,setShowManager]=useState(false);
  const [contacts,setContacts]=useState(()=>loadContacts());

  function handleNbPal(v){
    setNbPal(v);
    const n=parseInt(v)||0;
    if(n>0) setMl((n*0.4).toFixed(1));
  }
  function handleCompute(){
    const r=calculate({
      destType,dept,postalCodeBE,country,nbPal,ml,
      weight:shipMode==='poids'?weight:0,
      filterMode
    });
    setResults(r);
  }
  function saveContacts(c){setContacts(c);setShowManager(false);}

  const top3=results?.slice(0,3)||[];

  const seg=(v,label,active)=>(
    <button onClick={()=>setFilterMode(v)} style={{padding:'8px 16px',borderRadius:8,border:'1px solid',cursor:'pointer',fontSize:12,fontWeight:500,
      background:active?'rgba(34,211,238,.12)':'transparent',
      borderColor:active?'#22d3ee':'#1e293b',
      color:active?'#22d3ee':'#94a3b8'}}>
      {label}
    </button>
  );

  return (
    <div style={{fontFamily:'Segoe UI,system-ui,sans-serif',background:ss.bg,minHeight:'100vh',color:ss.text,padding:'20px 16px'}}>
      {showManager&&<ContactManager contacts={contacts} onSave={saveContacts} onClose={()=>setShowManager(false)}/>}
      <div style={{maxWidth:900,margin:'0 auto'}}>

        {/* Header */}
        <div style={{display:'flex',alignItems:'flex-start',justifyContent:'space-between',marginBottom:24,flexWrap:'wrap',gap:12}}>
          <div>
            <h1 style={{fontSize:22,fontWeight:800,color:'#22d3ee',margin:'0 0 3px',letterSpacing:-.5}}>Comparateur Transport</h1>
            <p style={{fontSize:12,color:ss.muted,margin:0}}>Coupé · Coquelle · Ceva · Dimotrans · Heppner — départ Roubaix</p>
          </div>
          <button onClick={()=>setShowManager(true)}
            style={{...ss.ghost,gap:7}}>
            <IconSettings/> Gérer les contacts
          </button>
        </div>

        {/* Form card */}
        <div style={{background:ss.card,border:'1px solid #1e293b',borderRadius:16,padding:24,marginBottom:20}}>

          {/* Row 1: destination + filter */}
          <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:20,marginBottom:20}}>
            <div>
              <label style={ss.label}>Destination</label>
              <div style={{display:'flex',gap:6,flexWrap:'wrap'}}>
                {[['france','🇫🇷 France'],['belgique','🇧🇪 Belgique'],['international','🌍 International']].map(([v,l])=>(
                  <button key={v} onClick={()=>{setDestType(v);setResults(null);}}
                    style={{padding:'7px 12px',borderRadius:8,border:'1px solid',cursor:'pointer',fontSize:12,fontWeight:500,
                      background:destType===v?'rgba(34,211,238,.12)':'transparent',
                      borderColor:destType===v?'#22d3ee':'#1e293b',
                      color:destType===v?'#22d3ee':'#94a3b8'}}>
                    {l}
                  </button>
                ))}
              </div>
            </div>
            <div>
              <label style={ss.label}>Type de livraison</label>
              <div style={{display:'flex',gap:6,flexWrap:'wrap'}}>
                {seg('all','Tous',filterMode==='all')}
                {seg('express','⚡ Express (J+1)',filterMode==='express')}
                {seg('standard','Standard (J+2)',filterMode==='standard')}
                {seg('slow','Lent (J+3+)',filterMode==='slow')}
              </div>
            </div>
          </div>

          {/* Row 2: destination input */}
          <div style={{marginBottom:20}}>
            <label style={ss.label}>
              {destType==='france'?'Département (01-95)':destType==='belgique'?'Code postal belge (4 chiffres)':'Pays de destination'}
            </label>
            {destType==='france'&&(
              <input type="text" value={dept} onChange={e=>{setDept(e.target.value);setResults(null);}}
                placeholder="59" maxLength={3} style={{...ss.input,maxWidth:160}}/>
            )}
            {destType==='belgique'&&(
              <input type="text" value={postalCodeBE} onChange={e=>{setPostalCodeBE(e.target.value);setResults(null);}}
                placeholder="1000" maxLength={4} style={{...ss.input,maxWidth:160}}/>
            )}
            {destType==='international'&&(
              <select value={country} onChange={e=>{setCountry(e.target.value);setResults(null);}}
                style={{...ss.input,maxWidth:300}}>
                {Object.entries(COUNTRY_NAMES).sort((a,b)=>a[1].localeCompare(b[1],'fr')).map(([code,name])=>(
                  <option key={code} value={code}>{name} ({code})</option>
                ))}
              </select>
            )}
          </div>

          {/* Row 3: envoi */}
          <div style={{marginBottom:20}}>
            <label style={ss.label}>Envoi</label>
            <div style={{display:'flex',gap:8,marginBottom:14}}>
              {[['pal','📦 Palettes + ML'],['poids','⚖ Au poids (kg)']].map(([v,l])=>(
                <button key={v} onClick={()=>{setShipMode(v);setResults(null);}}
                  style={{padding:'7px 14px',borderRadius:8,border:'1px solid',cursor:'pointer',fontSize:12,fontWeight:500,
                    background:shipMode===v?'rgba(34,211,238,.12)':'transparent',
                    borderColor:shipMode===v?'#22d3ee':'#1e293b',
                    color:shipMode===v?'#22d3ee':'#94a3b8'}}>
                  {l}
                </button>
              ))}
            </div>

            {shipMode==='pal'?(
              <div style={{display:'flex',gap:14,flexWrap:'wrap'}}>
                <div style={{flex:'0 0 160px'}}>
                  <label style={{...ss.label,marginBottom:4}}>Nb palettes</label>
                  <input type="number" value={nbPal} min={1} max={33} onChange={e=>handleNbPal(e.target.value)} style={ss.input}/>
                </div>
                <div style={{flex:'0 0 160px'}}>
                  <label style={{...ss.label,marginBottom:4}}>Mètres linéaires</label>
                  <input type="number" value={ml} step={0.1} min={0.1} onChange={e=>setMl(e.target.value)} style={ss.input}/>
                  <p style={{fontSize:10,color:'#94a3b8',margin:'4px 0 0'}}>Auto : {parseInt(nbPal)||1} pal × 0.4 = {((parseInt(nbPal)||1)*0.4).toFixed(1)} ML</p>
                </div>
              </div>
            ):(
              <div style={{flex:'0 0 200px'}}>
                <label style={{...ss.label,marginBottom:4}}>Poids total (kg)</label>
                <input type="number" value={weight} min={1} onChange={e=>setWeight(e.target.value)} style={{...ss.input,maxWidth:200}}/>
              </div>
            )}
          </div>

          <button onClick={handleCompute}
            style={{width:'100%',background:'#22d3ee',color:'#0a0e17',border:'none',borderRadius:10,padding:'13px',fontSize:15,fontWeight:800,cursor:'pointer',letterSpacing:-.2}}>
            Trouver le meilleur transporteur →
          </button>
        </div>

        {/* Results */}
        {results!==null&&(
          results.length===0?(
            <div style={{background:ss.card,border:'1px solid #1e293b',borderRadius:14,padding:40,textAlign:'center',color:ss.muted}}>
              <div style={{fontSize:32,marginBottom:12}}>📭</div>
              <div style={{fontSize:15,fontWeight:600,marginBottom:6}}>Aucun tarif disponible</div>
              <div style={{fontSize:12}}>Vérifiez le département, les paramètres d'envoi ou changez le filtre.</div>
            </div>
          ):(
            <>
              {/* Top 3 cards */}
              <div style={{marginBottom:20}}>
                <h2 style={{fontSize:12,fontWeight:700,color:ss.muted,textTransform:'uppercase',letterSpacing:1,margin:'0 0 14px'}}>
                  Meilleurs résultats — {results.length} option{results.length>1?'s':''} trouvée{results.length>1?'s':''}
                </h2>
                <div style={{display:'grid',gridTemplateColumns:'repeat(auto-fit,minmax(240px,1fr))',gap:14}}>
                  {top3.map((r,i)=><ResultCard key={i} result={r} rank={i} contacts={contacts}/>)}
                </div>
              </div>

              {/* Full table */}
              {results.length>3&&(
                <div style={{background:ss.card,border:'1px solid #1e293b',borderRadius:14,overflow:'hidden'}}>
                  <div style={{padding:'12px 20px',borderBottom:'1px solid #1e293b'}}>
                    <span style={{fontSize:13,fontWeight:600,color:'#cbd5e1'}}>Toutes les options ({results.length})</span>
                  </div>
                  <div style={{overflowX:'auto'}}>
                    <table style={{width:'100%',borderCollapse:'collapse'}}>
                      <thead>
                        <tr style={{background:'#0f172a'}}>
                          {['#','Transporteur','Mode','Délai','Prix HT','Contact'].map(h=>(
                            <th key={h} style={{padding:'10px 16px',textAlign:'left',color:'#22d3ee',fontWeight:700,fontSize:10,textTransform:'uppercase',letterSpacing:.5,borderBottom:'1px solid #1e293b',whiteSpace:'nowrap'}}>{h}</th>
                          ))}
                        </tr>
                      </thead>
                      <tbody>
                        {results.map((r,i)=><ResultRow key={i} result={r} rank={i} contacts={contacts}/>)}
                      </tbody>
                    </table>
                  </div>
                  <p style={{fontSize:10,color:'#94a3b8',padding:'8px 16px',margin:0}}>
                    Tarifs HT · Départ Roubaix · Sources : grilles 2023-2025 · Prix indicatifs, hors surcharges éventuelles.
                  </p>
                </div>
              )}
            </>
          )
        )}
      </div>
    </div>
  );
}

// Montage : page autonome (#root) ou MyExpe (#transport-comparateur-root). Ré-exécution via window.__mysifaTransportTryMount après re-render SPA.
function tryMount(){
  if (typeof React === "undefined" || !ReactDOM || !ReactDOM.createRoot) return;
  var el = document.getElementById("transport-comparateur-root") || document.getElementById("root");
  if (!el || el.dataset.mysifaTransportMounted === "1") return;
  el.dataset.mysifaTransportMounted = "1";
  var r = ReactDOM.createRoot(el);
  window.__transportReactRoot = r;
  r.render(React.createElement(App));
}
window.__mysifaTransportTryMount = tryMount;
tryMount();
